class DirectoryEntry:
    def __init__(self, name, inode):
        self.name = name
        self.inode = inode
        self.next = None  # For chaining

class HashDirectory:
    def __init__(self, size=100):
        self.size = size
        self.table = [None] * size

    def _hash(self, filename):
        return hash(filename) % self.size

    def insert(self, filename, inode):
        index = self._hash(filename)
        entry = DirectoryEntry(filename, inode)
        entry.next = self.table[index]
        self.table[index] = entry

    def search(self, filename):
        index = self._hash(filename)
        current = self.table[index]
        while current:
            if current.name == filename:
                return current.inode
            current = current.next
        return None

# Average Time Complexity: O(1), Worst: O(n)

typedef struct {
    char filename[255];      // File name
    uint32_t inode;          // Inode number
    uint32_t size;           // File size in bytes
    uint16_t permissions;    // Read/Write/Execute
    uint16_t created_time;  // Creation timestamp
    uint16_t modified_time; // Last modification
    uint16_t access_time;   // Last access time
    uint32_t first_block;   // First data block pointer
    uint8_t  file_type;     // Regular file/Directory
    uint8_t  link_count;    // Number of hard links
} DirectoryEntry;

